from dataclasses import dataclass
from typing import Literal

@dataclass
class Decision:
    kind: Literal["done", "tool_call", "mixed", "truncated"]
    text: str | None  # present if kind in ("done", "mixed")
    tool_calls: list  # present if kind in ("tool_call", "mixed")

def classify_decision(response) -> Decision:
    if response.stop_reason == "max_tokens":
        return Decision(kind="truncated", text=None, tool_calls=[])

    text_blocks = [b for b in response.content if b.type == "text"]
    tool_blocks = [b for b in response.content if b.type == "tool_use"]
    text = text_blocks[0].text if text_blocks else None

    if response.stop_reason == "end_turn":
        return Decision(kind="done", text=text, tool_calls=[])

    if response.stop_reason == "tool_use":
        if text:
            return Decision(kind="mixed", text=text, tool_calls=tool_blocks)
        return Decision(kind="tool_call", text=None, tool_calls=tool_blocks)

    return Decision(kind="done", text=text, tool_calls=[])

# Usage in the loop:
decision = classify_decision(response)
if decision.kind == "done":
    return decision.text
if decision.kind == "truncated":
    raise RuntimeError("Response truncated — context too long")
if decision.kind in ("tool_call", "mixed"):
    if decision.text:
        stream_to_user(decision.text)  # show intermediate reasoning
    results = dispatch_tools(decision.tool_calls)
    messages.append({"role": "user", "content": results})

import json
from datetime import datetime, timezone

def log_decision(turn: int, response, tool_results: list | None = None):
    entry = {
        "ts": datetime.now(timezone.utc).isoformat(),
        "turn": turn,
        "stop_reason": response.stop_reason,
        "blocks": [
            {
                "type": b.type,
                "tool_name": getattr(b, "name", None),
                "tool_input": getattr(b, "input", None),
                "text_preview": getattr(b, "text", "")[:120] if hasattr(b, "text") else None,
            }
            for b in response.content
        ],
        "usage": {
            "input_tokens": response.usage.input_tokens,
            "output_tokens": response.usage.output_tokens,
        },
    }
    if tool_results:
        entry["tool_results"] = [
            {
                "id": r.get("tool_use_id"),
                "is_error": r.get("is_error", False),
                "preview": str(r.get("content", ""))[:120],
            }
            for r in tool_results
        ]
    print(json.dumps(entry, indent=2))

# In the loop:
for i in range(max_turns):
