import anthropic
import json

client = anthropic.Anthropic()

EXTRACT_TOOL = {
    "name": "extract_issue_summary",
    "description": "Extract a structured summary of the GitHub issue.",
    "input_schema": {
        "type": "object",
        "properties": {
            "title": {"type": "string", "description": "One-line issue title"},
            "severity": {
                "type": "string",
                "enum": ["critical", "high", "medium", "low"],
                "description": "Estimated severity"
            },
            "affected_components": {
                "type": "array",
                "items": {"type": "string"},
                "description": "List of components affected"
            },
            "reproducible": {
                "type": "boolean",
                "description": "Whether the issue is reliably reproducible"
            },
            "suggested_assignee": {
                "type": "string",
                "description": "GitHub username of best-fit assignee, or empty string"
            },
        },
        "required": ["title", "severity", "affected_components", "reproducible"],
    },
}

def extract_issue_summary(issue_body: str) -> dict:
    response = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=512,
        tools=[EXTRACT_TOOL],
        tool_choice={"type": "any"},  # must call a tool
        messages=[{
            "role": "user",
            "content": f"Analyse this GitHub issue and extract a structured summary:\n\n{issue_body}",
        }],
    )
    # With tool_choice: any, the first content block is always tool_use
    tool_block = next(b for b in response.content if b.type == "tool_use")
    return tool_block.input  # already a dict — no JSON parsing needed

# Usage
result = extract_issue_summary(
    "Login button crashes on iOS 17 when dark mode is enabled. "
