"""Decision evaluation harness.

Run: python eval_decisions.py
Each case asserts that the model calls the expected tool (or none).
"""
import anthropic

client = anthropic.Anthropic()

TOOLS = [
    {
        "name": "read_file",
        "description": (
            "Read the full content of a specific file when you already know its path. "
            "Use this after you have identified the file you need."
        ),
        "input_schema": {
            "type": "object",
            "properties": {"path": {"type": "string"}},
            "required": ["path"],
        },
    },
    {
        "name": "search_code",
        "description": (
            "Search for files or symbols by pattern when you do not yet know the exact path. "
            "Use this before read_file when exploring an unfamiliar codebase."
        ),
        "input_schema": {
            "type": "object",
            "properties": {"query": {"type": "string"}},
            "required": ["query"],
        },
    },
]

SYSTEM = "You are a code-review agent. Read files and answer questions about the code."

CASES = [
    # (task, expected_tool_name or None for end_turn)
    ("Read the file at src/auth/login.py", "read_file"),
    ("Find all files related to authentication", "search_code"),
    ("What is 2 + 2?", None),  # no tool needed
]

for task, expected_tool in CASES:
    response = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=256,
        system=SYSTEM,
        tools=TOOLS,
        messages=[{"role": "user", "content": task}],
        temperature=0,
    )
    tool_calls = [b.name for b in response.content if b.type == "tool_use"]
    if expected_tool is None:
        assert not tool_calls, f"Expected no tool, got {tool_calls} for: {task!r}"
    else:
        assert expected_tool in tool_calls, (
            f"Expected {expected_tool!r}, got {tool_calls} for: {task!r}"
        )
    print(f"PASS: {task!r} → {tool_calls or 'end_turn'}")
